// --- From: script_state.js ---
let db, currentUser, chatPanel, chatInput, chatSendBtn, chatMessages, apiSettingsModalOverlay, newChatBtn, newProjectBtn, sessionListContainer, chatSessionTitle, deleteSessionBtn, chatWelcomeMessage, searchSessionsInput, aiModelSelector, apiSettingsBtn, apiKeyInput, verifyApiKeyBtn, apiKeyStatus, apiModelSelect, maxOutputTokensInput, tokenUsageDisplay, resetTokenUsageBtn, apiSettingsSaveBtn, apiSettingsCancelBtn;
let currentSessionId = null;
let localProjectsCache = [], localChatSessionsCache = [];
let unsubscribeFromProjects = null, unsubscribeFromChatSessions = null;
let newlyCreatedProjectId = null;
const activeTimers = {};
let userApiSettings = { provider: null, apiKey: "", selectedModel: "", availableModels: [], maxOutputTokens: 2048, tokenUsage: { prompt: 0, completion: 0 }};
const canvasId = "chatbot-mvp-instance-01";
const appId = "AileyBailey_Global_Space";

// --- From: script_ui_helpers.js ---
function makePanelDraggable(panel) { if(!panel) return; const h=panel.querySelector(".panel-header"); if(!h) return; let d=!1,o={x:0,y:0}; h.addEventListener("mousedown",e=>{if(e.target.closest("button,input,select,textarea"))return;d=!0;o={x:panel.offsetLeft-e.clientX,y:panel.offsetTop-e.clientY};document.addEventListener("mousemove",m);document.addEventListener("mouseup",u)}); const m=e=>{if(d){panel.style.left=(e.clientX+o.x)+"px";panel.style.top=(e.clientY+o.y)+"px"}}; const u=()=>{d=!1;document.removeEventListener("mousemove",m);document.removeEventListener("mouseup",u)};}
function togglePanel(panel, forceShow = null) { if(!panel)return; const s=forceShow!==null?forceShow:panel.style.display!=="flex"; panel.style.display=s?"flex":"none";}
function showModal(msg, onConfirm) { const d=document.createElement("div"); d.className="custom-modal-overlay"; d.style.display="flex"; d.innerHTML=`<div class="custom-modal" style="text-align:center;"><div>${msg}</div><div class="custom-modal-actions"><button id="m_cancel" class="modal-btn" style="background:grey">취소</button><button id="m_ok" class="modal-btn" style="background:#8C6D46">확인</button></div></div>`; document.body.appendChild(d); document.getElementById("m_ok").onclick=()=>{onConfirm();d.remove()}; document.getElementById("m_cancel").onclick=()=>d.remove(); }

// --- From: script_firebase.js ---
async function initializeFirebase() { try { const config = JSON.parse(__firebase_config); if(!firebase.apps.length) firebase.initializeApp(config); const auth = firebase.auth(); db = firebase.firestore(); await auth.signInAnonymously(); currentUser = auth.currentUser; if (currentUser) { const path = `artifacts/${appId}/users/${currentUser.uid}/chatHistories/${canvasId}`; projectsCollectionRef = db.collection(`${path}/projects`); chatSessionsCollectionRef = db.collection(`${path}/sessions`); listenToProjects(); listenToChatSessions(); } } catch(e) { console.error("Firebase init failed:", e); } }
function getRelativeDateGroup(ts, pinned=false) { if(pinned) return {key:0, label:"📌 고정됨"}; if(!ts) return {key:99, label:"날짜 정보 없음"}; const n=new Date(), d=ts.toDate();n.setHours(0,0,0,0);d.setHours(0,0,0,0);const diff=n.getTime()-d.getTime();const days=diff/(1000*60*60*24);if(days<1)return{key:1,label:"오늘"};if(days<2)return{key:2,label:"어제"};if(days<7)return{key:3,label:"지난 7일"};return{key:4,label:"이전 대화"};}
function listenToProjects(){ if(!projectsCollectionRef)return; if(unsubscribeFromProjects)unsubscribeFromProjects(); unsubscribeFromProjects = projectsCollectionRef.orderBy("updatedAt", "desc").onSnapshot(s=>{const old=localProjectsCache.slice(); localProjectsCache=s.docs.map(d=>({id:d.id, isExpanded:old.find(p=>p.id===d.id)?.isExpanded??true, ...d.data()})); renderSidebarContent(); if(newlyCreatedProjectId){startProjectRename(newlyCreatedProjectId); newlyCreatedProjectId=null;} });}
function listenToChatSessions(){ if(!chatSessionsCollectionRef)return; if(unsubscribeFromChatSessions)unsubscribeFromChatSessions(); unsubscribeFromChatSessions = chatSessionsCollectionRef.orderBy("updatedAt", "desc").onSnapshot(s=>{localChatSessionsCache = s.docs.map(d=>({id:d.id, ...d.data()})); renderSidebarContent(); if(currentSessionId){const data=localChatSessionsCache.find(s=>s.id===currentSessionId); if(!data)handleNewChat(); else renderChatMessages(data);} });}

// --- From: script_chat_data.js ---
async function createNewProject(){const name=getNewProjectDefaultName();try{const ref=await projectsCollectionRef.add({name:name,createdAt:firebase.firestore.FieldValue.serverTimestamp(),updatedAt:firebase.firestore.FieldValue.serverTimestamp()});newlyCreatedProjectId=ref.id}catch(e){console.error(e)}}
async function renameProject(id,name){if(!name||!id)return;try{await projectsCollectionRef.doc(id).update({name:name,updatedAt:firebase.firestore.FieldValue.serverTimestamp()})}catch(e){console.error(e)}}
async function deleteProject(id){const p=localProjectsCache.find(p=>p.id===id);if(!p)return;showModal(`프로젝트 삭제?`,async()=>{try{const batch=db.batch();const sessions=localChatSessionsCache.filter(s=>s.projectId===id);sessions.forEach(s=>{batch.update(chatSessionsCollectionRef.doc(s.id),{projectId:null})});batch.delete(projectsCollectionRef.doc(id));await batch.commit()}catch(e){console.error(e)}})}
async function moveSessionToProject(id,pId){try{const targetId = pId === "null" ? null : pId; await chatSessionsCollectionRef.doc(id).update({projectId:targetId});if(targetId){await projectsCollectionRef.doc(targetId).update({updatedAt:firebase.firestore.FieldValue.serverTimestamp()})}}catch(e){console.error(e)}}
async function toggleChatPin(id){const s=localChatSessionsCache.find(s=>s.id===id);if(!s)return;try{await chatSessionsCollectionRef.doc(id).update({isPinned:!s.isPinned,updatedAt:firebase.firestore.FieldValue.serverTimestamp()})}catch(e){console.error(e)}}
async function renameSession(id,title){if(!title||!id)return;try{await chatSessionsCollectionRef.doc(id).update({title:title,updatedAt:firebase.firestore.FieldValue.serverTimestamp()})}catch(e){console.error(e)}}
function handleDeleteSession(id){if(!id)return;const s=localChatSessionsCache.find(s=>s.id===id);if(!s)return;showModal(`대화 삭제?`,()=>{chatSessionsCollectionRef.doc(id).delete().then(()=>{if(currentSessionId===id)handleNewChat()})})}

// --- From: script_api_settings.js ---
function createApiSettingsModal(){const m=document.createElement("div");m.id="api-settings-modal-overlay";m.className="custom-modal-overlay";m.innerHTML=`<div class="custom-modal api-settings-modal"><h3>API 설정</h3><div class="api-key-wrapper"><input type="password" id="api-key-input" placeholder="API 키 입력"><button id="verify-api-key-btn">검증</button></div><div id="api-key-status"></div><select id="api-model-select" disabled><option>키 검증 필요</option></select><div class="custom-modal-actions"><button id="api-settings-cancel-btn" class="modal-btn">취소</button><button id="api-settings-save-btn" class="modal-btn">저장</button></div></div>`;document.body.appendChild(m);apiSettingsModalOverlay=m;apiKeyInput=document.getElementById("api-key-input");verifyApiKeyBtn=document.getElementById("verify-api-key-btn");apiKeyStatus=document.getElementById("api-key-status");apiModelSelect=document.getElementById("api-model-select");apiSettingsSaveBtn=document.getElementById("api-settings-save-btn");apiSettingsCancelBtn=document.getElementById("api-settings-cancel-btn");}
function openApiSettingsModal(){loadApiSettings();apiKeyInput.value=userApiSettings.apiKey;populateModelSelector(userApiSettings.availableModels,userApiSettings.provider,userApiSettings.selectedModel);if(userApiSettings.apiKey){apiKeyStatus.textContent="✅ 키 활성화됨";}else{apiKeyStatus.textContent=""} apiSettingsModalOverlay.style.display="flex"}
function closeApiSettingsModal(){apiSettingsModalOverlay.style.display="none"}
function loadApiSettings(){const s=localStorage.getItem("userApiSettings");if(s)userApiSettings=JSON.parse(s)}
function saveApiSettings(close=true){const k=apiKeyInput.value.trim();if(k){userApiSettings.apiKey=k;userApiSettings.selectedModel=apiModelSelect.value;if(apiModelSelect&&apiModelSelect.options.length>0&&!apiModelSelect.disabled)userApiSettings.availableModels=Array.from(apiModelSelect.options).map(o=>o.value)}else{userApiSettings={provider:null,apiKey:"",selectedModel:"",availableModels:[]}} localStorage.setItem("userApiSettings",JSON.stringify(userApiSettings));if(close)closeApiSettingsModal()}
function detectProvider(k){if(k.startsWith("sk-ant-api"))return"anthropic";if(k.startsWith("sk-"))return"openai";if(k.length>35&&k.startsWith("AIza"))return"google_paid";return null}
async function handleVerifyApiKey(){const k=apiKeyInput.value.trim();if(!k)return;const p=detectProvider(k);if(!p){apiKeyStatus.textContent="알 수 없는 키 형식";return} userApiSettings.provider=p;apiKeyStatus.textContent="검증 중...";verifyApiKeyBtn.disabled=!0;try{const m=await fetchAvailableModels(p,k);populateModelSelector(m,p);apiKeyStatus.textContent="✅ 검증 완료!";apiModelSelect.disabled=!1}catch(e){apiKeyStatus.textContent=`❌ 검증 실패: ${e.message}`}finally{verifyApiKeyBtn.disabled=!1}}
async function fetchAvailableModels(p,k){if(p==="openai"){const r=await fetch("https://api.openai.com/v1/models",{headers:{"Authorization":`Bearer ${k}`}});if(!r.ok)throw new Error("모델 로드 실패");const d=await r.json();return d.data.filter(m=>m.id.includes("gpt")).map(m=>m.id).sort().reverse()}if(p==="anthropic")return["claude-3-opus-20240229","claude-3-sonnet-20240229","claude-3-haiku-20240307"];return[]}
function populateModelSelector(m,p,s=null){apiModelSelect.innerHTML="";const e=m||[];if(e.length>0){e.forEach(id=>{const o=document.createElement("option");o.value=id;o.textContent=id;if(id===s)o.selected=!0;apiModelSelect.appendChild(o)});apiModelSelect.disabled=!1}else{apiModelSelect.innerHTML="<option>모델 없음</option>";apiModelSelect.disabled=!0}}

// --- From: script_chat_engine.js ---
async function handleChatSend(){const q=chatInput.value.trim();if(!q)return;chatInput.value="";chatInput.disabled=!0;chatSendBtn.disabled=!0;const userMsg={role:"user",content:q,timestamp:new Date()};let sessionRef,isNew=!1;if(!currentSessionId){isNew=!0;const p=document.querySelector(".project-header.active-drop-target")?.closest(".project-container").dataset.projectId||null;chatWelcomeMessage.style.display="none";chatMessages.style.display="flex";renderChatMessages({messages:[userMsg,{role:"ai",status:"loading"}]});const newSession={title:q.substring(0,40),messages:[userMsg],projectId:p,createdAt:firebase.firestore.FieldValue.serverTimestamp()};sessionRef=await chatSessionsCollectionRef.add(newSession);currentSessionId=sessionRef.id}else{sessionRef=chatSessionsCollectionRef.doc(currentSessionId);const d=localChatSessionsCache.find(s=>s.id===currentSessionId);renderChatMessages({messages:[...d.messages,userMsg,{role:"ai",status:"loading"}]});await sessionRef.update({messages:firebase.firestore.FieldValue.arrayUnion(userMsg)})} try{let aiRes;if(userApiSettings.provider&&userApiSettings.apiKey){const req=buildApiRequest(userApiSettings.provider,userApiSettings.selectedModel,[userMsg],userApiSettings.maxOutputTokens);const res=await fetch(req.url,req.options);if(!res.ok)throw new Error(`API Error ${res.status}`);const result=await res.json();aiRes=parseApiResponse(userApiSettings.provider,result).content}else{const p=`[REASONING_START]SUMMARY:Do I need reasoning?|||DETAIL:Think step by step.[REASONING_END]Answer query in Korean. Query: "${q}"`;const res=await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash-latest:generateContent?key=${atob("QUl6YVN5Q0pfd0VEX2hTQk1XUk5GWHF3N21iVjNXTmVPbWJaeHNF")}`,{method:"POST",body:JSON.stringify({contents:[{parts:[{text:p}]}]})});if(!res.ok)throw new Error("Google API Error");const result=await res.json();aiRes=result.candidates[0].content.parts[0].text} const aiMsg={role:"ai",content:aiRes,timestamp:new Date()};await sessionRef.update({messages:firebase.firestore.FieldValue.arrayUnion(aiMsg)})}catch(e){console.error(e);await sessionRef.update({messages:firebase.firestore.FieldValue.arrayUnion({role:"ai",content:`오류: ${e.message}`})})}finally{chatInput.disabled=!1;chatSendBtn.disabled=!1;if(isNew)selectSession(currentSessionId)}}
function renderChatMessages(data){if(!chatMessages||!data)return;chatMessages.innerHTML="";const f=document.createDocumentFragment();data.messages.forEach((m,i)=>{if(m.role==="user"){const d=document.createElement("div");d.className="chat-message user";d.textContent=m.content;f.appendChild(d)}else if(m.role==="ai"){if(m.status==="loading"){const l=document.createElement("div");l.className="reasoning-block loading";l.innerHTML=`<div class="reasoning-header"><span class="reasoning-summary blinking-cursor">AI가 생각하는 중...</span></div>`;f.appendChild(l);return} const c=m.content;const r=/^\[REASONING_START\]([\s\S]*?)\[REASONING_END\]/;const match=c.match(r);if(match){const block=document.createElement("div");block.className="reasoning-block";block.innerHTML=`<div class="reasoning-header"><span class="toggle-icon">▶</span><span>AI의 추론 과정</span></div><div class="reasoning-content">${match[1].replace(/\n/g,"<br>")}</div>`;f.appendChild(block);const answer=document.createElement("div");answer.className="chat-message ai";answer.textContent=c.replace(r,"").trim();f.appendChild(answer)}else{const d=document.createElement("div");d.className="chat-message ai";d.textContent=c;f.appendChild(d)}}});chatMessages.appendChild(f);chatMessages.scrollTop=chatMessages.scrollHeight}
function buildApiRequest(p,m,h,t){const hist=h.map(msg=>({role:msg.role==="ai"?"assistant":"user",content:msg.content}));if(p==="openai")return{url:"https://api.openai.com/v1/chat/completions",options:{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${userApiSettings.apiKey}`},body:JSON.stringify({model:m,messages:hist,max_tokens:t||2048})}};if(p==="anthropic")return{url:"https://api.anthropic.com/v1/messages",options:{method:"POST",headers:{"Content-Type":"application/json","x-api-key":userApiSettings.apiKey,"anthropic-version":"2023-06-01"},body:JSON.stringify({model:m,messages:hist,max_tokens:t||2048})}};throw new Error("Unsupported provider")}
function parseApiResponse(p,r){try{if(p==="openai")return{content:r.choices[0].message.content};if(p==="anthropic")return{content:r.content[0].text};}catch(e){console.error(e)}return{content:"API 응답 파싱 오류"}}

// --- From: script_chat_ui.js ---
function renderSidebarContent(){if(!sessionListContainer)return;const term=searchSessionsInput.value.toLowerCase();sessionListContainer.innerHTML="";const f=document.createDocumentFragment();const projects=localProjectsCache;if(projects.length>0){const h=document.createElement("div");h.className="session-group-header";h.textContent="📁 프로젝트";f.appendChild(h);projects.forEach(p=>f.appendChild(createProjectContainer(p,term)))} const unassigned=localChatSessionsCache.filter(s=>!s.projectId);if(unassigned.length>0){const h=document.createElement("div");h.className="session-group-header";h.textContent="💬 일반 대화";f.appendChild(h);const groups=unassigned.reduce((acc,s)=>{const g=getRelativeDateGroup(s.updatedAt||s.createdAt,s.isPinned);if(!acc[g.label])acc[g.label]={key:g.key,items:[]};acc[g.label].items.push(s);return acc},{});Object.keys(groups).sort((a,b)=>groups[a].key-groups[b].key).forEach(label=>{const h=document.createElement("div");h.className="date-group-header";h.textContent=label;f.appendChild(h);groups[label].items.forEach(s=>f.appendChild(createSessionItem(s)))})} sessionListContainer.appendChild(f)}
function createProjectContainer(p,term){const c=document.createElement("div");c.className="project-container";c.dataset.projectId=p.id;c.innerHTML=`<div class="project-header"><span class="project-toggle-icon ${p.isExpanded?"expanded":""}">▶</span><span class="project-title">${p.name}</span><button class="project-actions-btn">...</button></div><div class="sessions-in-project ${p.isExpanded?"expanded":""}"></div>`;const sessions=c.querySelector(".sessions-in-project");localChatSessionsCache.filter(s=>s.projectId===p.id).forEach(s=>sessions.appendChild(createSessionItem(s)));return c}
function createSessionItem(s){const i=document.createElement("div");i.className="session-item";i.dataset.sessionId=s.id;if(s.id===currentSessionId)i.classList.add("active");i.innerHTML=`<div class="session-item-title">${s.title||"새 대화"}</div><button class="session-pin-btn ${s.isPinned?"pinned-active":""}">📌</button>`;return i}
function removeContextMenu(){document.querySelector(".project-context-menu")?.remove()}
function showProjectContextMenu(id,btn){removeContextMenu();const m=document.createElement("div");m.className="project-context-menu";m.style.position="absolute";m.style.top=`${btn.getBoundingClientRect().bottom}px`;m.style.right="5px";m.innerHTML=`<button data-action="rename">이름 변경</button><button data-action="delete">삭제</button>`;sessionListContainer.appendChild(m);m.style.display="block";m.onclick=e=>{e.stopPropagation();const a=e.target.dataset.action;if(a==="rename")startProjectRename(id);if(a==="delete")deleteProject(id);removeContextMenu()}}

// --- From: script_chat_app.js ---
function getNewProjectDefaultName(){const n="새 프로젝트";let i=1;while(localProjectsCache.some(p=>p.name===`${n} ${i}`)){i++}return`${n} ${i}`}
function toggleProjectExpansion(id){const p=localProjectsCache.find(p=>p.id===id);if(p){p.isExpanded=!p.isExpanded;renderSidebarContent()}}
function startProjectRename(id){const t=document.querySelector(`.project-container[data-project-id="${id}"] .project-title`);if(!t)return;const o=t.textContent,i=document.createElement("input");i.type="text";i.className="project-title-input";i.value=o;t.replaceWith(i);i.focus();const f=()=>{const n=i.value.trim();if(n&&n!==o)renameProject(id,n);else renderSidebarContent()};i.onblur=f;i.onkeydown=e=>{if(e.key==="Enter")i.blur()}}
function selectSession(id){if(!id)return;const d=localChatSessionsCache.find(s=>s.id===id);if(!d)return;currentSessionId=id;Object.values(activeTimers).forEach(t=>t.forEach(clearInterval));renderSidebarContent();chatWelcomeMessage.style.display="none";chatMessages.style.display="flex";renderChatMessages(d);chatSessionTitle.textContent=d.title||"대화";deleteSessionBtn.style.display="inline-block";chatInput.disabled=!1;chatSendBtn.disabled=!1;chatInput.focus()}
function handleNewChat(){currentSessionId=null;Object.values(activeTimers).forEach(t=>t.forEach(clearInterval));renderSidebarContent();if(chatMessages)chatMessages.innerHTML="";if(chatWelcomeMessage)chatWelcomeMessage.style.display="flex";if(chatSessionTitle)chatSessionTitle.textContent="AI 러닝메이트";if(deleteSessionBtn)deleteSessionBtn.style.display="none";if(chatInput){chatInput.disabled=!1;chatInput.value="";}if(chatSendBtn)chatSendBtn.disabled=!1}

// --- From: script_main_chat.js ---
document.addEventListener("DOMContentLoaded", ()=>{
chatPanel=document.getElementById("chat-panel"); chatInput=document.getElementById("chat-input"); chatSendBtn=document.getElementById("chat-send-btn"); chatMessages=document.getElementById("chat-messages"); newChatBtn=document.getElementById("new-chat-btn"); newProjectBtn=document.getElementById("new-project-btn"); sessionListContainer=document.getElementById("session-list-container"); chatSessionTitle=document.getElementById("chat-session-title"); deleteSessionBtn=document.getElementById("delete-session-btn"); chatWelcomeMessage=document.getElementById("chat-welcome-message"); searchSessionsInput=document.getElementById("search-sessions-input"); aiModelSelector=document.getElementById("ai-model-selector"); const chatToggleBtn=document.getElementById("chat-toggle-btn");
createApiSettingsModal();
const chatHeader=document.querySelector("#chat-main-view .panel-header > div"); if(chatHeader){apiSettingsBtn=document.createElement("span");apiSettingsBtn.id="api-settings-btn";apiSettingsBtn.title="API 설정";apiSettingsBtn.innerHTML=`<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor"><path d="M12,8A4,4 0 0,1 16,12A4,4 0 0,1 12,16A4,4 0 0,1 8,12A4,4 0 0,1 12,8M12,10A2,2 0 0,0 10,12A2,2 0 0,0 12,14A2,2 0 0,0 14,12A2,2 0 0,0 12,10M19.03,7.39L20.45,5.97C20,5.46 19.54,5 19.03,4.55L17.61,5.97C16.07,4.74 14.12,4 12,4C9.88,4 7.93,4.74 6.39,5.97L5,4.55C4.5,5 4,5.46 3.55,5.97L4.97,7.39C3.74,8.93 3,10.88 3,13C3,15.12 3.74,17.07 4.97,18.61L3.55,20.03C4,20.54 4.5,21 5,21.45L6.39,20.03C7.93,21.26 9.88,22 12,22C14.12,22 16.07,21.26 17.61,20.03L19.03,21.45C19.54,21 20,20.54 20.45,20.03L19.03,18.61C20.26,17.07 21,15.12 21,13C21,10.88 20.26,8.93 19.03,7.39Z" /></svg>`;chatHeader.appendChild(apiSettingsBtn)}
loadApiSettings();
initializeFirebase().then(()=>{makePanelDraggable(chatPanel);handleNewChat()});
attachChatEventListeners();
});
function attachChatEventListeners(){ document.getElementById("chat-input-form").addEventListener("submit", e=>{e.preventDefault();handleChatSend()}); newChatBtn.addEventListener("click", handleNewChat); newProjectBtn.addEventListener("click", createNewProject); apiSettingsBtn.addEventListener("click", openApiSettingsModal); apiSettingsSaveBtn.addEventListener("click", ()=>saveApiSettings()); apiSettingsCancelBtn.addEventListener("click", closeApiSettingsModal); verifyApiKeyBtn.addEventListener("click", handleVerifyApiKey); document.getElementById("chat-toggle-btn").addEventListener("click",()=>togglePanel(chatPanel)); sessionListContainer.addEventListener("click", e=>{const s=e.target.closest(".session-item");if(s){selectSession(s.dataset.sessionId);return}const p=e.target.closest(".project-header");if(p){const b=e.target.closest(".project-actions-btn");if(b)showProjectContextMenu(p.closest(".project-container").dataset.projectId,b);else toggleProjectExpansion(p.closest(".project-container").dataset.projectId)}}); sessionListContainer.addEventListener("contextmenu", e=>{const s=e.target.closest(".session-item");if(s){e.preventDefault();showSessionContextMenu(s.dataset.sessionId, e.clientX, e.clientY)}});}

